#include<bits/stdc++.h>
using namespace std;
int d[100010],v[100010],a[100010];
const double eps=1e-8;
int p[100010],flag[100010];
vector<pair<int,int>> vec;
bool cmp(pair<int,int> a,pair<int,int> b)
{
    return a.second<b.second;
}
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        vec.clear();
        int n,m,l,V;
        scanf("%d%d%d%d",&n,&m,&l,&V);
        for(int i=1;i<=n;i++)
        {
            scanf("%d%d%d",&d[i],&v[i],&a[i]);
        }
        for(int i=1;i<=m;i++)
        {
            scanf("%d",&p[i]);
        }
        for(int i=1;i<=n;i++)
        {
            if(d[i]>p[m])
            {
                continue;
            }
            if(a[i]==0)
            {
                if(v[i]<=V)
                {
                    continue;
                }
                int l=lower_bound(p+1,p+1+m,d[i])-p;
                int r=m;
                flag[i]=1;
                vec.push_back(make_pair(l,r));
            }
            else if(a[i]<0)
            {
                if(v[i]<=V)
                {
                    continue;
                }
                double tmp=d[i]+((V*V)-(v[i]*v[i]))*1.0/(a[i]*2);
                int l=1,r=m,best=0;
                while(l<=r)
                {
                    int mid=(l+r)>>1;
                    if(p[mid]<tmp)
                    {
                        l=mid+1;
                        best=mid;
                    }
                    else
                    {
                        r=mid-1;
                    }
                }
                if(best==0)
                {
                    continue;
                }
                int R=best;
                l=1,r=m,best=0;
                int L=lower_bound(p+1,p+1+m,d[i])-p;
                if(L<=R)
                {
                    flag[i]=1;
                    vec.push_back(make_pair(L,R));
                }
            }
            else
            {
                if(v[i]>V)
                {
                    flag[i]=1;
                    int L=lower_bound(p+1,p+1+m,d[i])-p,R=m;
                    vec.push_back(make_pair(L,R));
                }
                else
                {
                    double tmp=d[i]+((V*V)-(v[i]*v[i]))*1.0/(a[i]*2);
                    int l=1,r=m,best=0;
                    while(l<=r)
                    {
                        int mid=(l+r)>>1;
                        if(p[mid]>tmp)
                        {
                            best=mid;
                            r=mid-1;
                        }
                        else
                        {
                            l=mid+1;
                        }
                    }
                    if(best==0)
                    {
                        continue;
                    }
                    int L=best,R=m;
                    flag[i]=1;
                    vec.push_back(make_pair(L,R));
                }
            }
        }
        // int cnt=0;
        // for(int i=1;i<=n;i++)if(flag[i])
        // {
        //     printf("%d : ",i);
        //     for(int j=vec[cnt].first;j<=vec[cnt].second;j++)
        //     {
        //         printf("%d ",p[j]);
        //     }
        //     printf("\n");
        //     cnt++;
        // }
        int R=-1,ans=0;
        sort(vec.begin(),vec.end(),cmp);
        for(auto i:vec)
        {
            if(R>=i.first)
            {
                continue;
            }
            ans++;
            R=i.second;
        }
        printf("%d %d\n",(int)(vec.size()),m-ans);
    }
    return 0;
}
